364:         tasks.clearPendingTasksToCreate();
365:         tasks.addPendingActiveTasksToCreate(pendingTasksToCreate(activeTasksToCreate));
366:         tasks.addPendingStandbyTasksToCreate(pendingTasksToCreate(standbyTasksToCreate));
367:         
368:         // first rectify all existing tasks:
369:         // 1. for tasks that are already owned, just update input partitions / resume and skip re-creating them
370:         // 2. for tasks that have changed active/standby status, just recycle and skip re-creating them
371:         // 3. otherwise, close them since they are no longer owned
372:         final Map<TaskId, RuntimeException> failedTasks = new LinkedHashMap<>();
373:         if (stateUpdater == null) {
374:             handleTasksWithoutStateUpdater(activeTasksToCreate, standbyTasksToCreate, tasksToRecycle, tasksToCloseClean);
375:         } else {
