396:     // Wrap and throw the exception in the following order
397:     // if at least one of the exception is a non-streams exception, then wrap and throw since it should be handled by thread's handler
398:     // if at least one of the exception is a streams exception, then directly throw since it should be handled by thread's handler
399:     // if at least one of the exception is a task-migrated exception, then directly throw since it indicates all tasks are lost
400:     // otherwise, all the exceptions are task-corrupted, then merge their tasks and throw a single one
401:     // TODO: move task-corrupted and task-migrated out of the public errors package since they are internal errors and always be
402:     //       handled by Streams library itself
403:     private void maybeThrowTaskExceptions(final Map<TaskId, RuntimeException> taskExceptions) {
404:         if (!taskExceptions.isEmpty()) {
405:             log.error("Get exceptions for the following tasks: {}", taskExceptions);
406: 
407:             final Set<TaskId> aggregatedCorruptedTaskIds = new HashSet<>();
408:             StreamsException lastFatal = null;
409:             TaskMigratedException lastTaskMigrated = null;
410:             for (final Map.Entry<TaskId, RuntimeException> entry : taskExceptions.entrySet()) {
411:                 final TaskId taskId = entry.getKey();
412:                 final RuntimeException exception = entry.getValue();
413: 
414:                 if (exception instanceof StreamsException) {
415:                     if (exception instanceof TaskMigratedException) {
416:                         lastTaskMigrated = (TaskMigratedException) exception;
417:                     } else if (exception instanceof TaskCorruptedException) {
418:                         log.warn("Encounter corrupted task " + taskId + ", will group it with other corrupted tasks " +
419:                             "and handle together", exception);
420:                         aggregatedCorruptedTaskIds.add(taskId);
421:                     } else {
422:                         ((StreamsException) exception).setTaskId(taskId);
423:                         lastFatal = (StreamsException) exception;
424:                     }
425:                 } else if (exception instanceof KafkaException) {
426:                     lastFatal = new StreamsException(exception, taskId);
427:                 } else {
428:                     lastFatal = new StreamsException("Encounter unexpected fatal error for task " + taskId, exception, taskId);
429:                 }
430:             }
431: 
432:             if (lastFatal != null) {
433:                 throw lastFatal;
434:             } else if (lastTaskMigrated != null) {
435:                 throw lastTaskMigrated;
436:             } else {
437:                 throw new TaskCorruptedException(aggregatedCorruptedTaskIds);
438:             }
439:         }
440:     }
